#[derive(Debug, Clone, PartialEq, Eq, Serialize)]
pub struct NativeVulkanCapabilities {
    pub built: bool,
    pub experimental: bool,
    pub default_enabled: bool,
    pub reuses_native_wayland_host: bool,
    pub owns_layer_shell_surface_now: bool,
    pub owns_vulkan_instance_now: bool,
    pub owns_vulkan_device_now: bool,
    pub owns_wayland_vulkan_surface_now: bool,
    pub owns_swapchain_now: bool,
    pub renders_frames_now: bool,
    pub consumes_render_sync: bool,
    pub direct_video_memory_status: &'static str,
    pub unsafe_policy: &'static str,
}

pub fn capabilities() -> NativeVulkanCapabilities {
    NativeVulkanCapabilities {
        built: true,
        experimental: true,
        default_enabled: false,
        reuses_native_wayland_host: true,
        owns_layer_shell_surface_now: true,
        owns_vulkan_instance_now: true,
        owns_vulkan_device_now: true,
        owns_wayland_vulkan_surface_now: true,
        owns_swapchain_now: true,
        renders_frames_now: true,
        consumes_render_sync: false,
        direct_video_memory_status: "contract-only: target is importable DMABuf/EGLImage/Vulkan image sampling",
        unsafe_policy: "unsafe is allowed inside audited Vulkan/Wayland/DMABuf FFI boundaries only",
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_queue_present_frame(
    swapchain_loader: &ash::khr::swapchain::Device,
    present_queue: vk::Queue,
    swapchain: vk::SwapchainKHR,
    image_index: u32,
    wait_semaphore: vk::Semaphore,
    operation: &'static str,
) -> Result<(), NativeVulkanError> {
    let wait_semaphores = [wait_semaphore];
    let swapchains = [swapchain];
    let image_indices = [image_index];
    let present_info = vk::PresentInfoKHR::default()
        .wait_semaphores(&wait_semaphores)
        .swapchains(&swapchains)
        .image_indices(&image_indices);
    unsafe {
        swapchain_loader
            .queue_present(present_queue, &present_info)
            .map_err(|result| NativeVulkanError::Vulkan { operation, result })
            .map(|_| ())
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
#[allow(clippy::too_many_arguments)]
fn native_vulkan_present_video_preroll_frame(
    device: &ash::Device,
    swapchain_loader: &ash::khr::swapchain::Device,
    renderer: &NativeVulkanVideoRenderer,
    present_queue_mutex: &std::sync::Mutex<()>,
    submit_queue: vk::Queue,
    present_queue: vk::Queue,
    swapchain: vk::SwapchainKHR,
    swapchain_images: &[vk::Image],
    swapchain_image_layouts: &mut [vk::ImageLayout],
    command_buffer: vk::CommandBuffer,
) -> Result<(), NativeVulkanError> {
    let semaphore_create_info = vk::SemaphoreCreateInfo::default();
    let image_available = unsafe { device.create_semaphore(&semaphore_create_info, None) }
        .map_err(|result| NativeVulkanError::Vulkan {
            operation: "vkCreateSemaphore(video preroll image available)",
            result,
        })?;
    let render_finished = match unsafe { device.create_semaphore(&semaphore_create_info, None) } {
        Ok(semaphore) => semaphore,
        Err(result) => {
            unsafe {
                device.destroy_semaphore(image_available, None);
            }
            return Err(NativeVulkanError::Vulkan {
                operation: "vkCreateSemaphore(video preroll render finished)",
                result,
            });
        }
    };
    let fence_create_info = vk::FenceCreateInfo::default();
    let render_fence = match unsafe { device.create_fence(&fence_create_info, None) } {
        Ok(fence) => fence,
        Err(result) => {
            unsafe {
                device.destroy_semaphore(render_finished, None);
                device.destroy_semaphore(image_available, None);
            }
            return Err(NativeVulkanError::Vulkan {
                operation: "vkCreateFence(video preroll render)",
                result,
            });
        }
    };

    let result = (|| -> Result<(), NativeVulkanError> {
        let (image_index, _) = unsafe {
            swapchain_loader.acquire_next_image(
                swapchain,
                u64::MAX,
                image_available,
                vk::Fence::null(),
            )
        }
        .map_err(|result| NativeVulkanError::Vulkan {
            operation: "vkAcquireNextImageKHR(video preroll)",
            result,
        })?;
        let image_index = image_index as usize;
        let swapchain_image = swapchain_images.get(image_index).copied().ok_or_else(|| {
            NativeVulkanError::Video(format!(
                "video preroll acquired image {image_index} but swapchain has {} images",
                swapchain_images.len()
            ))
        })?;
        let swapchain_old_layout = swapchain_image_layouts
            .get(image_index)
            .copied()
            .ok_or_else(|| {
                NativeVulkanError::Video(format!(
                    "video preroll acquired image {image_index} but layout cache has {} entries",
                    swapchain_image_layouts.len()
                ))
            })?;
        renderer.record_clear_frame(
            device,
            command_buffer,
            image_index,
            swapchain_image,
            swapchain_old_layout,
        )?;
        swapchain_image_layouts[image_index] = renderer.target_final_layout();

        let wait_semaphores = [image_available];
        let wait_stages = [vk::PipelineStageFlags::COLOR_ATTACHMENT_OUTPUT];
        let command_buffers = [command_buffer];
        let signal_semaphores = [render_finished];
        let submit_info = vk::SubmitInfo::default()
            .wait_semaphores(&wait_semaphores)
            .wait_dst_stage_mask(&wait_stages)
            .command_buffers(&command_buffers)
            .signal_semaphores(&signal_semaphores);
        {
            let _present_queue_guard = present_queue_mutex.lock().map_err(|_| {
                NativeVulkanError::Video(
                    "video preroll present queue mutex was poisoned".to_owned(),
                )
            })?;
            unsafe {
                device
                    .queue_submit(submit_queue, &[submit_info], render_fence)
                    .map_err(|result| NativeVulkanError::Vulkan {
                        operation: "vkQueueSubmit(video preroll)",
                        result,
                    })?;
            }
        }
        {
            let _present_queue_guard = present_queue_mutex.lock().map_err(|_| {
                NativeVulkanError::Video(
                    "video preroll present queue mutex was poisoned".to_owned(),
                )
            })?;
            native_vulkan_queue_present_frame(
                swapchain_loader,
                present_queue,
                swapchain,
                image_index as u32,
                render_finished,
                "vkQueuePresentKHR(video preroll)",
            )?;
        }
        unsafe {
            device
                .wait_for_fences(&[render_fence], true, u64::MAX)
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkWaitForFences(video preroll)",
                    result,
                })?;
            device
                .queue_wait_idle(submit_queue)
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkQueueWaitIdle(video preroll submit queue)",
                    result,
                })?;
            device
                .queue_wait_idle(present_queue)
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkQueueWaitIdle(video preroll present queue)",
                    result,
                })?;
        }
        Ok(())
    })();

    unsafe {
        device.destroy_fence(render_fence, None);
        device.destroy_semaphore(render_finished, None);
        device.destroy_semaphore(image_available, None);
    }

    result
}

#[derive(Debug)]
pub enum NativeVulkanError {
    Wayland(NativeWaylandError),
    Loading(String),
    Vulkan {
        operation: &'static str,
        result: vk::Result,
    },
    MissingDeviceExtension(&'static str),
    MissingPresentQueue,
    MissingSurfaceFormat,
    UnsupportedSwapchainUsage(&'static str),
    InvalidSwapchainExtent,
    StaticImage(String),
    Video(String),
    MissingMemoryType(&'static str),
}

impl fmt::Display for NativeVulkanError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            Self::Wayland(err) => write!(f, "{err}"),
            Self::Loading(err) => write!(f, "load Vulkan entry: {err}"),
            Self::Vulkan { operation, result } => write!(f, "{operation}: {result:?}"),
            Self::MissingDeviceExtension(extension) => {
                write!(f, "selected Vulkan device is missing {extension}")
            }
            Self::MissingPresentQueue => {
                write!(f, "no Vulkan graphics queue can present to Wayland surface")
            }
            Self::MissingSurfaceFormat => write!(f, "Wayland Vulkan surface has no formats"),
            Self::UnsupportedSwapchainUsage(usage) => {
                write!(
                    f,
                    "Wayland Vulkan surface does not support {usage} swapchain usage"
                )
            }
            Self::InvalidSwapchainExtent => write!(f, "invalid Vulkan swapchain extent"),
            Self::StaticImage(err) => write!(f, "static image error: {err}"),
            Self::Video(err) => write!(f, "video error: {err}"),
            Self::MissingMemoryType(label) => write!(f, "missing Vulkan memory type for {label}"),
        }
    }
}

impl std::error::Error for NativeVulkanError {}

impl From<NativeWaylandError> for NativeVulkanError {
    fn from(err: NativeWaylandError) -> Self {
        Self::Wayland(err)
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
