#[cfg(feature = "native-vulkan-gst-video")]
impl NativeVulkanVideoRenderer {
    fn new(
        device: &ash::Device,
        swapchain_format: vk::Format,
        extent: vk::Extent2D,
        swapchain_image_views: &[vk::ImageView],
    ) -> Result<Self, NativeVulkanError> {
        Self::new_with_target_final_layout(
            device,
            swapchain_format,
            extent,
            swapchain_image_views,
            vk::ImageLayout::PRESENT_SRC_KHR,
        )
    }

    fn new_with_target_final_layout(
        device: &ash::Device,
        target_format: vk::Format,
        extent: vk::Extent2D,
        target_image_views: &[vk::ImageView],
        target_final_layout: vk::ImageLayout,
    ) -> Result<Self, NativeVulkanError> {
        Self::new_with_descriptor_set_count(
            device,
            target_format,
            extent,
            target_image_views,
            target_final_layout,
            1,
        )
    }

    fn new_with_descriptor_set_count(
        device: &ash::Device,
        target_format: vk::Format,
        extent: vk::Extent2D,
        target_image_views: &[vk::ImageView],
        target_final_layout: vk::ImageLayout,
        descriptor_set_count: u32,
    ) -> Result<Self, NativeVulkanError> {
        let descriptor_set_count = descriptor_set_count.max(1);
        let render_pass =
            native_vulkan_create_video_render_pass(device, target_format, target_final_layout)?;
        let framebuffers = native_vulkan_create_video_framebuffers(
            device,
            render_pass,
            extent,
            target_image_views,
        )?;
        let bindings = [
            native_vulkan_video_sampler_binding(0),
            native_vulkan_video_sampler_binding(1),
        ];
        let descriptor_set_layout_info =
            vk::DescriptorSetLayoutCreateInfo::default().bindings(&bindings);
        let descriptor_set_layout =
            unsafe { device.create_descriptor_set_layout(&descriptor_set_layout_info, None) }
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkCreateDescriptorSetLayout(video)",
                    result,
                })?;
        let pool_sizes = [vk::DescriptorPoolSize {
            ty: vk::DescriptorType::COMBINED_IMAGE_SAMPLER,
            descriptor_count: descriptor_set_count.saturating_mul(2),
        }];
        let descriptor_pool_info = vk::DescriptorPoolCreateInfo::default()
            .max_sets(descriptor_set_count)
            .pool_sizes(&pool_sizes);
        let descriptor_pool =
            match unsafe { device.create_descriptor_pool(&descriptor_pool_info, None) } {
                Ok(pool) => pool,
                Err(result) => {
                    unsafe {
                        device.destroy_descriptor_set_layout(descriptor_set_layout, None);
                        for framebuffer in framebuffers {
                            device.destroy_framebuffer(framebuffer, None);
                        }
                        device.destroy_render_pass(render_pass, None);
                    }
                    return Err(NativeVulkanError::Vulkan {
                        operation: "vkCreateDescriptorPool(video)",
                        result,
                    });
                }
            };
        let set_layouts = vec![descriptor_set_layout; descriptor_set_count as usize];
        let descriptor_set_allocate_info = vk::DescriptorSetAllocateInfo::default()
            .descriptor_pool(descriptor_pool)
            .set_layouts(&set_layouts);
        let descriptor_sets =
            match unsafe { device.allocate_descriptor_sets(&descriptor_set_allocate_info) } {
                Ok(sets) => sets,
                Err(result) => {
                    unsafe {
                        device.destroy_descriptor_pool(descriptor_pool, None);
                        device.destroy_descriptor_set_layout(descriptor_set_layout, None);
                        for framebuffer in framebuffers {
                            device.destroy_framebuffer(framebuffer, None);
                        }
                        device.destroy_render_pass(render_pass, None);
                    }
                    return Err(NativeVulkanError::Vulkan {
                        operation: "vkAllocateDescriptorSets(video)",
                        result,
                    });
                }
            };
        let sampler_info = vk::SamplerCreateInfo::default()
            .mag_filter(vk::Filter::LINEAR)
            .min_filter(vk::Filter::LINEAR)
            .mipmap_mode(vk::SamplerMipmapMode::NEAREST)
            .address_mode_u(vk::SamplerAddressMode::CLAMP_TO_EDGE)
            .address_mode_v(vk::SamplerAddressMode::CLAMP_TO_EDGE)
            .address_mode_w(vk::SamplerAddressMode::CLAMP_TO_EDGE)
            .max_lod(1.0);
        let sampler = match unsafe { device.create_sampler(&sampler_info, None) } {
            Ok(sampler) => sampler,
            Err(result) => {
                unsafe {
                    device.destroy_descriptor_pool(descriptor_pool, None);
                    device.destroy_descriptor_set_layout(descriptor_set_layout, None);
                    for framebuffer in framebuffers {
                        device.destroy_framebuffer(framebuffer, None);
                    }
                    device.destroy_render_pass(render_pass, None);
                }
                return Err(NativeVulkanError::Vulkan {
                    operation: "vkCreateSampler(video)",
                    result,
                });
            }
        };
        let push_constant_ranges = [vk::PushConstantRange::default()
            .stage_flags(vk::ShaderStageFlags::VERTEX)
            .offset(0)
            .size(16)];
        let pipeline_set_layouts = [descriptor_set_layout];
        let pipeline_layout_info = vk::PipelineLayoutCreateInfo::default()
            .set_layouts(&pipeline_set_layouts)
            .push_constant_ranges(&push_constant_ranges);
        let pipeline_layout =
            match unsafe { device.create_pipeline_layout(&pipeline_layout_info, None) } {
                Ok(layout) => layout,
                Err(result) => {
                    unsafe {
                        device.destroy_sampler(sampler, None);
                        device.destroy_descriptor_pool(descriptor_pool, None);
                        device.destroy_descriptor_set_layout(descriptor_set_layout, None);
                        for framebuffer in framebuffers {
                            device.destroy_framebuffer(framebuffer, None);
                        }
                        device.destroy_render_pass(render_pass, None);
                    }
                    return Err(NativeVulkanError::Vulkan {
                        operation: "vkCreatePipelineLayout(video)",
                        result,
                    });
                }
            };
        let pipeline =
            match native_vulkan_create_video_pipeline(device, render_pass, pipeline_layout, extent)
            {
                Ok(pipeline) => pipeline,
                Err(err) => {
                    unsafe {
                        device.destroy_pipeline_layout(pipeline_layout, None);
                        device.destroy_sampler(sampler, None);
                        device.destroy_descriptor_pool(descriptor_pool, None);
                        device.destroy_descriptor_set_layout(descriptor_set_layout, None);
                        for framebuffer in framebuffers {
                            device.destroy_framebuffer(framebuffer, None);
                        }
                        device.destroy_render_pass(render_pass, None);
                    }
                    return Err(err);
                }
            };

        Ok(Self {
            render_pass,
            framebuffers,
            descriptor_set_layout,
            descriptor_pool,
            descriptor_sets,
            pipeline_layout,
            pipeline,
            sampler,
            extent,
            target_final_layout,
        })
    }

    fn target_final_layout(&self) -> vk::ImageLayout {
        self.target_final_layout
    }

    fn update_descriptors(&mut self, device: &ash::Device, texture: &NativeVulkanVideoTexture) {
        self.update_descriptors_for_set_index(device, 0, texture)
            .expect("video renderer always has descriptor set 0");
    }

    fn update_descriptors_for_set_index(
        &mut self,
        device: &ash::Device,
        descriptor_set_index: usize,
        texture: &NativeVulkanVideoTexture,
    ) -> Result<(), NativeVulkanError> {
        let descriptor_set = self
            .descriptor_sets
            .get(descriptor_set_index)
            .copied()
            .ok_or_else(|| {
                NativeVulkanError::Video(format!(
                    "video renderer descriptor set index {descriptor_set_index} is out of range for {} sets",
                    self.descriptor_sets.len()
                ))
            })?;
        let image_infos = [
            vk::DescriptorImageInfo::default()
                .sampler(self.sampler)
                .image_view(texture.y_view())
                .image_layout(texture.image_layout()),
            vk::DescriptorImageInfo::default()
                .sampler(self.sampler)
                .image_view(texture.uv_view())
                .image_layout(texture.image_layout()),
        ];
        let writes = [
            vk::WriteDescriptorSet::default()
                .dst_set(descriptor_set)
                .dst_binding(0)
                .descriptor_type(vk::DescriptorType::COMBINED_IMAGE_SAMPLER)
                .image_info(&image_infos[0..1]),
            vk::WriteDescriptorSet::default()
                .dst_set(descriptor_set)
                .dst_binding(1)
                .descriptor_type(vk::DescriptorType::COMBINED_IMAGE_SAMPLER)
                .image_info(&image_infos[1..2]),
        ];
        unsafe {
            device.update_descriptor_sets(&writes, &[]);
        }
        Ok(())
    }

    fn record_clear_frame(
        &self,
        device: &ash::Device,
        command_buffer: vk::CommandBuffer,
        image_index: usize,
        swapchain_image: vk::Image,
        swapchain_old_layout: vk::ImageLayout,
    ) -> Result<(), NativeVulkanError> {
        unsafe {
            device
                .reset_command_buffer(command_buffer, vk::CommandBufferResetFlags::empty())
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkResetCommandBuffer(video preroll)",
                    result,
                })?;
            let begin_info = vk::CommandBufferBeginInfo::default()
                .flags(vk::CommandBufferUsageFlags::ONE_TIME_SUBMIT);
            device
                .begin_command_buffer(command_buffer, &begin_info)
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkBeginCommandBuffer(video preroll)",
                    result,
                })?;

            let swapchain_to_attachment = vk::ImageMemoryBarrier::default()
                .old_layout(swapchain_old_layout)
                .new_layout(vk::ImageLayout::COLOR_ATTACHMENT_OPTIMAL)
                .src_queue_family_index(vk::QUEUE_FAMILY_IGNORED)
                .dst_queue_family_index(vk::QUEUE_FAMILY_IGNORED)
                .image(swapchain_image)
                .subresource_range(native_vulkan_color_subresource_range())
                .src_access_mask(vk::AccessFlags::empty())
                .dst_access_mask(vk::AccessFlags::COLOR_ATTACHMENT_WRITE);
            device.cmd_pipeline_barrier(
                command_buffer,
                vk::PipelineStageFlags::TOP_OF_PIPE | vk::PipelineStageFlags::ALL_COMMANDS,
                vk::PipelineStageFlags::COLOR_ATTACHMENT_OUTPUT,
                vk::DependencyFlags::empty(),
                &[],
                &[],
                &[swapchain_to_attachment],
            );

            let render_area = vk::Rect2D {
                offset: vk::Offset2D { x: 0, y: 0 },
                extent: self.extent,
            };
            let render_pass_begin = vk::RenderPassBeginInfo::default()
                .render_pass(self.render_pass)
                .framebuffer(self.framebuffers[image_index])
                .render_area(render_area);
            device.cmd_begin_render_pass(
                command_buffer,
                &render_pass_begin,
                vk::SubpassContents::INLINE,
            );
            let clear_value = vk::ClearValue {
                color: vk::ClearColorValue {
                    float32: [0.0, 0.0, 0.0, 1.0],
                },
            };
            let clear_attachment = vk::ClearAttachment::default()
                .aspect_mask(vk::ImageAspectFlags::COLOR)
                .color_attachment(0)
                .clear_value(clear_value);
            let clear_rect = vk::ClearRect::default()
                .rect(render_area)
                .base_array_layer(0)
                .layer_count(1);
            device.cmd_clear_attachments(command_buffer, &[clear_attachment], &[clear_rect]);
            device.cmd_end_render_pass(command_buffer);

            device
                .end_command_buffer(command_buffer)
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkEndCommandBuffer(video preroll)",
                    result,
                })?;
        }
        Ok(())
    }

    fn record_frame(
        &self,
        device: &ash::Device,
        command_buffer: vk::CommandBuffer,
        image_index: usize,
        swapchain_image: vk::Image,
        swapchain_old_layout: vk::ImageLayout,
        texture: &NativeVulkanVideoTexture,
        fit: FitMode,
    ) -> Result<(), NativeVulkanError> {
        self.record_frame_with_descriptor_set_index(
            device,
            command_buffer,
            image_index,
            swapchain_image,
            swapchain_old_layout,
            texture,
            fit,
            0,
            None,
        )
    }

    #[allow(clippy::too_many_arguments)]
    fn record_frame_with_descriptor_set_index(
        &self,
        device: &ash::Device,
        command_buffer: vk::CommandBuffer,
        image_index: usize,
        swapchain_image: vk::Image,
        swapchain_old_layout: vk::ImageLayout,
        texture: &NativeVulkanVideoTexture,
        fit: FitMode,
        descriptor_set_index: usize,
        display_copy_before_render: Option<NativeVulkanDecodedVideoDisplayCopyBeforeRender<'_>>,
    ) -> Result<(), NativeVulkanError> {
        let display_copy_before_render = display_copy_before_render
            .map(|copy| copy.to_command())
            .transpose()?;
        self.record_frame_with_descriptor_set_index_with_copy_command(
            device,
            command_buffer,
            image_index,
            swapchain_image,
            swapchain_old_layout,
            texture,
            fit,
            descriptor_set_index,
            display_copy_before_render,
        )
    }

    #[allow(clippy::too_many_arguments)]
    fn record_frame_with_descriptor_set_index_with_copy_command(
        &self,
        device: &ash::Device,
        command_buffer: vk::CommandBuffer,
        image_index: usize,
        swapchain_image: vk::Image,
        swapchain_old_layout: vk::ImageLayout,
        texture: &NativeVulkanVideoTexture,
        fit: FitMode,
        descriptor_set_index: usize,
        display_copy_before_render: Option<NativeVulkanDecodedVideoDisplayCopyBeforeRenderCommand>,
    ) -> Result<(), NativeVulkanError> {
        let descriptor_set = self
            .descriptor_sets
            .get(descriptor_set_index)
            .copied()
            .ok_or_else(|| {
                NativeVulkanError::Video(format!(
                    "video renderer descriptor set index {descriptor_set_index} is out of range for {} sets",
                    self.descriptor_sets.len()
                ))
            })?;
        unsafe {
            device
                .reset_command_buffer(command_buffer, vk::CommandBufferResetFlags::empty())
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkResetCommandBuffer(video)",
                    result,
                })?;
            let begin_info = vk::CommandBufferBeginInfo::default()
                .flags(vk::CommandBufferUsageFlags::ONE_TIME_SUBMIT);
            device
                .begin_command_buffer(command_buffer, &begin_info)
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkBeginCommandBuffer(video)",
                    result,
                })?;

            if let Some(copy) = display_copy_before_render {
                native_vulkan_cmd_decoded_video_display_copy_for_graphics_image(
                    device,
                    command_buffer,
                    copy.source_image,
                    copy.source_base_array_layer,
                    copy.display_image,
                    copy.display_base_array_layer,
                    copy.display_old_layout,
                    copy.extent,
                )?;
            }

            let swapchain_to_attachment = vk::ImageMemoryBarrier::default()
                .old_layout(swapchain_old_layout)
                .new_layout(vk::ImageLayout::COLOR_ATTACHMENT_OPTIMAL)
                .src_queue_family_index(vk::QUEUE_FAMILY_IGNORED)
                .dst_queue_family_index(vk::QUEUE_FAMILY_IGNORED)
                .image(swapchain_image)
                .subresource_range(native_vulkan_color_subresource_range())
                .src_access_mask(vk::AccessFlags::empty())
                .dst_access_mask(vk::AccessFlags::COLOR_ATTACHMENT_WRITE);
            let texture_barriers = texture.shader_read_barriers();
            if texture_barriers.is_empty() {
                let barriers = [swapchain_to_attachment];
                device.cmd_pipeline_barrier(
                    command_buffer,
                    vk::PipelineStageFlags::TOP_OF_PIPE | vk::PipelineStageFlags::ALL_COMMANDS,
                    vk::PipelineStageFlags::COLOR_ATTACHMENT_OUTPUT
                        | vk::PipelineStageFlags::FRAGMENT_SHADER,
                    vk::DependencyFlags::empty(),
                    &[],
                    &[],
                    &barriers,
                );
            } else {
                let mut barriers = Vec::with_capacity(1 + texture_barriers.len());
                barriers.push(swapchain_to_attachment);
                barriers.extend(texture_barriers);
                device.cmd_pipeline_barrier(
                    command_buffer,
                    vk::PipelineStageFlags::TOP_OF_PIPE | vk::PipelineStageFlags::ALL_COMMANDS,
                    vk::PipelineStageFlags::COLOR_ATTACHMENT_OUTPUT
                        | vk::PipelineStageFlags::FRAGMENT_SHADER,
                    vk::DependencyFlags::empty(),
                    &[],
                    &[],
                    &barriers,
                );
            }

            let clear_values = [vk::ClearValue {
                color: vk::ClearColorValue {
                    float32: [0.0, 0.0, 0.0, 1.0],
                },
            }];
            let render_area = vk::Rect2D {
                offset: vk::Offset2D { x: 0, y: 0 },
                extent: self.extent,
            };
            let render_pass_begin = vk::RenderPassBeginInfo::default()
                .render_pass(self.render_pass)
                .framebuffer(self.framebuffers[image_index])
                .render_area(render_area)
                .clear_values(&clear_values);
            device.cmd_begin_render_pass(
                command_buffer,
                &render_pass_begin,
                vk::SubpassContents::INLINE,
            );
            device.cmd_bind_pipeline(
                command_buffer,
                vk::PipelineBindPoint::GRAPHICS,
                self.pipeline,
            );
            device.cmd_bind_descriptor_sets(
                command_buffer,
                vk::PipelineBindPoint::GRAPHICS,
                self.pipeline_layout,
                0,
                &[descriptor_set],
                &[],
            );
            let push = sampling::native_vulkan_video_fit_push_constants(
                fit,
                (texture.width(), texture.height()),
                (self.extent.width, self.extent.height),
            );
            let push_bytes = std::slice::from_raw_parts(
                push.as_ptr().cast::<u8>(),
                std::mem::size_of_val(&push),
            );
            device.cmd_push_constants(
                command_buffer,
                self.pipeline_layout,
                vk::ShaderStageFlags::VERTEX,
                0,
                push_bytes,
            );
            device.cmd_draw(command_buffer, 3, 1, 0, 0);
            device.cmd_end_render_pass(command_buffer);

            device
                .end_command_buffer(command_buffer)
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkEndCommandBuffer(video)",
                    result,
                })?;
        }
        Ok(())
    }

    fn destroy(self, device: &ash::Device) {
        unsafe {
            device.destroy_pipeline(self.pipeline, None);
            device.destroy_pipeline_layout(self.pipeline_layout, None);
            device.destroy_sampler(self.sampler, None);
            device.destroy_descriptor_pool(self.descriptor_pool, None);
            device.destroy_descriptor_set_layout(self.descriptor_set_layout, None);
            for framebuffer in self.framebuffers {
                device.destroy_framebuffer(framebuffer, None);
            }
            device.destroy_render_pass(self.render_pass, None);
        }
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_video_sampler_binding(binding: u32) -> vk::DescriptorSetLayoutBinding<'static> {
    vk::DescriptorSetLayoutBinding::default()
        .binding(binding)
        .descriptor_type(vk::DescriptorType::COMBINED_IMAGE_SAMPLER)
        .descriptor_count(1)
        .stage_flags(vk::ShaderStageFlags::FRAGMENT)
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_create_video_render_pass(
    device: &ash::Device,
    swapchain_format: vk::Format,
    final_layout: vk::ImageLayout,
) -> Result<vk::RenderPass, NativeVulkanError> {
    let color_attachment = vk::AttachmentDescription::default()
        .format(swapchain_format)
        .samples(vk::SampleCountFlags::TYPE_1)
        .load_op(vk::AttachmentLoadOp::DONT_CARE)
        .store_op(vk::AttachmentStoreOp::STORE)
        .stencil_load_op(vk::AttachmentLoadOp::DONT_CARE)
        .stencil_store_op(vk::AttachmentStoreOp::DONT_CARE)
        .initial_layout(vk::ImageLayout::COLOR_ATTACHMENT_OPTIMAL)
        .final_layout(final_layout);
    let color_attachment_ref = vk::AttachmentReference::default()
        .attachment(0)
        .layout(vk::ImageLayout::COLOR_ATTACHMENT_OPTIMAL);
    let color_attachment_refs = [color_attachment_ref];
    let subpass = vk::SubpassDescription::default()
        .pipeline_bind_point(vk::PipelineBindPoint::GRAPHICS)
        .color_attachments(&color_attachment_refs);
    let dependency = vk::SubpassDependency::default()
        .src_subpass(vk::SUBPASS_EXTERNAL)
        .dst_subpass(0)
        .src_stage_mask(vk::PipelineStageFlags::COLOR_ATTACHMENT_OUTPUT)
        .dst_stage_mask(vk::PipelineStageFlags::COLOR_ATTACHMENT_OUTPUT)
        .dst_access_mask(vk::AccessFlags::COLOR_ATTACHMENT_WRITE);
    let attachments = [color_attachment];
    let subpasses = [subpass];
    let dependencies = [dependency];
    let render_pass_info = vk::RenderPassCreateInfo::default()
        .attachments(&attachments)
        .subpasses(&subpasses)
        .dependencies(&dependencies);
    unsafe { device.create_render_pass(&render_pass_info, None) }.map_err(|result| {
        NativeVulkanError::Vulkan {
            operation: "vkCreateRenderPass(video)",
            result,
        }
    })
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_create_video_framebuffers(
    device: &ash::Device,
    render_pass: vk::RenderPass,
    extent: vk::Extent2D,
    swapchain_image_views: &[vk::ImageView],
) -> Result<Vec<vk::Framebuffer>, NativeVulkanError> {
    let mut framebuffers = Vec::with_capacity(swapchain_image_views.len());
    for view in swapchain_image_views {
        let attachments = [*view];
        let info = vk::FramebufferCreateInfo::default()
            .render_pass(render_pass)
            .attachments(&attachments)
            .width(extent.width)
            .height(extent.height)
            .layers(1);
        let framebuffer = match unsafe { device.create_framebuffer(&info, None) } {
            Ok(framebuffer) => framebuffer,
            Err(result) => {
                for framebuffer in framebuffers {
                    unsafe {
                        device.destroy_framebuffer(framebuffer, None);
                    }
                }
                return Err(NativeVulkanError::Vulkan {
                    operation: "vkCreateFramebuffer(video)",
                    result,
                });
            }
        };
        framebuffers.push(framebuffer);
    }
    Ok(framebuffers)
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_create_video_pipeline(
    device: &ash::Device,
    render_pass: vk::RenderPass,
    pipeline_layout: vk::PipelineLayout,
    extent: vk::Extent2D,
) -> Result<vk::Pipeline, NativeVulkanError> {
    let vertex_module = native_vulkan_create_shader_module(
        device,
        &NATIVE_VULKAN_VIDEO_VERTEX_SPIRV,
        "video vertex",
    )?;
    let fragment_module = match native_vulkan_create_shader_module(
        device,
        &NATIVE_VULKAN_VIDEO_FRAGMENT_SPIRV,
        "video fragment",
    ) {
        Ok(module) => module,
        Err(err) => {
            unsafe {
                device.destroy_shader_module(vertex_module, None);
            }
            return Err(err);
        }
    };
    let entry = c"main";
    let stages = [
        vk::PipelineShaderStageCreateInfo::default()
            .stage(vk::ShaderStageFlags::VERTEX)
            .module(vertex_module)
            .name(entry),
        vk::PipelineShaderStageCreateInfo::default()
            .stage(vk::ShaderStageFlags::FRAGMENT)
            .module(fragment_module)
            .name(entry),
    ];
    let vertex_input = vk::PipelineVertexInputStateCreateInfo::default();
    let input_assembly = vk::PipelineInputAssemblyStateCreateInfo::default()
        .topology(vk::PrimitiveTopology::TRIANGLE_LIST);
    let viewport = vk::Viewport {
        x: 0.0,
        y: 0.0,
        width: extent.width as f32,
        height: extent.height as f32,
        min_depth: 0.0,
        max_depth: 1.0,
    };
    let scissor = vk::Rect2D {
        offset: vk::Offset2D { x: 0, y: 0 },
        extent,
    };
    let viewports = [viewport];
    let scissors = [scissor];
    let viewport_state = vk::PipelineViewportStateCreateInfo::default()
        .viewports(&viewports)
        .scissors(&scissors);
    let rasterization = vk::PipelineRasterizationStateCreateInfo::default()
        .polygon_mode(vk::PolygonMode::FILL)
        .cull_mode(vk::CullModeFlags::NONE)
        .front_face(vk::FrontFace::COUNTER_CLOCKWISE)
        .line_width(1.0);
    let multisample = vk::PipelineMultisampleStateCreateInfo::default()
        .rasterization_samples(vk::SampleCountFlags::TYPE_1);
    let color_attachment = vk::PipelineColorBlendAttachmentState::default()
        .color_write_mask(
            vk::ColorComponentFlags::R
                | vk::ColorComponentFlags::G
                | vk::ColorComponentFlags::B
                | vk::ColorComponentFlags::A,
        )
        .blend_enable(false);
    let color_attachments = [color_attachment];
    let color_blend =
        vk::PipelineColorBlendStateCreateInfo::default().attachments(&color_attachments);
    let pipeline_info = vk::GraphicsPipelineCreateInfo::default()
        .stages(&stages)
        .vertex_input_state(&vertex_input)
        .input_assembly_state(&input_assembly)
        .viewport_state(&viewport_state)
        .rasterization_state(&rasterization)
        .multisample_state(&multisample)
        .color_blend_state(&color_blend)
        .layout(pipeline_layout)
        .render_pass(render_pass)
        .subpass(0);
    let pipelines = unsafe {
        device.create_graphics_pipelines(vk::PipelineCache::null(), &[pipeline_info], None)
    };
    unsafe {
        device.destroy_shader_module(fragment_module, None);
        device.destroy_shader_module(vertex_module, None);
    }
    pipelines
        .map(|pipelines| pipelines[0])
        .map_err(|(_, result)| NativeVulkanError::Vulkan {
            operation: "vkCreateGraphicsPipelines(video)",
            result,
        })
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_create_shader_module(
    device: &ash::Device,
    code: &[u32],
    label: &'static str,
) -> Result<vk::ShaderModule, NativeVulkanError> {
    let info = vk::ShaderModuleCreateInfo::default().code(code);
    unsafe { device.create_shader_module(&info, None) }.map_err(|result| {
        NativeVulkanError::Vulkan {
            operation: match label {
                "video vertex" => "vkCreateShaderModule(video vertex)",
                "video fragment" => "vkCreateShaderModule(video fragment)",
                _ => "vkCreateShaderModule(video)",
            },
            result,
        }
    })
}

#[cfg(feature = "native-vulkan-gst-video")]
enum NativeVulkanVideoTexture {
    Cuda(NativeVulkanCudaVideoTexture),
    Dmabuf(NativeVulkanDmabufVideoTexture),
    Decoded(NativeVulkanDecodedVideoTexture),
}

#[cfg(feature = "native-vulkan-gst-video")]
impl NativeVulkanVideoTexture {
    fn width(&self) -> u32 {
        match self {
            Self::Cuda(texture) => texture.width,
            Self::Dmabuf(texture) => texture.width,
            Self::Decoded(texture) => texture.width,
        }
    }

    fn height(&self) -> u32 {
        match self {
            Self::Cuda(texture) => texture.height,
            Self::Dmabuf(texture) => texture.height,
            Self::Decoded(texture) => texture.height,
        }
    }

    fn y_view(&self) -> vk::ImageView {
        match self {
            Self::Cuda(texture) => texture.y.view,
            Self::Dmabuf(texture) => texture.y_view,
            Self::Decoded(texture) => texture.y_view,
        }
    }

    fn uv_view(&self) -> vk::ImageView {
        match self {
            Self::Cuda(texture) => texture.uv.view,
            Self::Dmabuf(texture) => texture.uv_view,
            Self::Decoded(texture) => texture.uv_view,
        }
    }

    fn image_layout(&self) -> vk::ImageLayout {
        match self {
            Self::Cuda(_) | Self::Dmabuf(_) => vk::ImageLayout::GENERAL,
            Self::Decoded(texture) => texture.shader_layout,
        }
    }

    fn shader_read_barriers(&self) -> Vec<vk::ImageMemoryBarrier<'static>> {
        match self {
            Self::Cuda(texture) => texture.shader_read_barriers(),
            Self::Dmabuf(texture) => texture.shader_read_barriers(),
            Self::Decoded(texture) => texture.shader_read_barriers(),
        }
    }

    fn clone_decoded_for_present_frame_queue(
        &self,
    ) -> Result<NativeVulkanDecodedVideoTexture, NativeVulkanError> {
        match self {
            Self::Decoded(texture) => texture.clone_cached_views(),
            Self::Cuda(_) | Self::Dmabuf(_) => Err(NativeVulkanError::Video(
                "present-frame queue currently requires decoded video texture views".to_owned(),
            )),
        }
    }

    fn destroy(self, device: &ash::Device) {
        match self {
            Self::Cuda(texture) => texture.destroy(device),
            Self::Dmabuf(texture) => texture.destroy(device),
            Self::Decoded(texture) => texture.destroy(device),
        }
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
struct NativeVulkanDecodedVideoTexture {
    image: vk::Image,
    width: u32,
    height: u32,
    base_array_layer: u32,
    y_view: vk::ImageView,
    uv_view: vk::ImageView,
    owns_views: bool,
    source_layout: vk::ImageLayout,
    shader_layout: vk::ImageLayout,
    source_access: vk::AccessFlags,
}

#[cfg(feature = "native-vulkan-gst-video")]
impl NativeVulkanDecodedVideoTexture {
    fn new(
        device: &ash::Device,
        image: vk::Image,
        format: vk::Format,
        width: u32,
        height: u32,
        base_array_layer: u32,
        source_layout: vk::ImageLayout,
        source_access: vk::AccessFlags,
    ) -> Result<Self, NativeVulkanError> {
        if width == 0 || height == 0 || !width.is_multiple_of(2) || !height.is_multiple_of(2) {
            return Err(NativeVulkanError::Video(format!(
                "decoded {} texture requires non-zero even dimensions, got {width}x{height}",
                native_vulkan_format_label(format)
            )));
        }
        let plane_formats = native_vulkan_decoded_video_plane_formats(format)?;
        let y_view = native_vulkan_create_decoded_video_plane_view(
            device,
            image,
            vk::ImageAspectFlags::PLANE_0,
            plane_formats.y_view_format,
            base_array_layer,
            "y",
        )?;
        let uv_view = match native_vulkan_create_decoded_video_plane_view(
            device,
            image,
            vk::ImageAspectFlags::PLANE_1,
            plane_formats.uv_view_format,
            base_array_layer,
            "uv",
        ) {
            Ok(view) => view,
            Err(err) => {
                unsafe {
                    device.destroy_image_view(y_view, None);
                }
                return Err(err);
            }
        };
        Ok(Self {
            image,
            width,
            height,
            base_array_layer,
            y_view,
            uv_view,
            owns_views: true,
            source_layout,
            shader_layout: vk::ImageLayout::SHADER_READ_ONLY_OPTIMAL,
            source_access,
        })
    }

    fn from_cached_views(
        image: vk::Image,
        format: vk::Format,
        width: u32,
        height: u32,
        base_array_layer: u32,
        views: NativeVulkanDecodedVideoPlaneViews,
        source_layout: vk::ImageLayout,
        source_access: vk::AccessFlags,
    ) -> Result<Self, NativeVulkanError> {
        Self::from_cached_views_with_shader_layout(
            image,
            format,
            width,
            height,
            base_array_layer,
            views,
            source_layout,
            vk::ImageLayout::SHADER_READ_ONLY_OPTIMAL,
            source_access,
        )
    }

    #[allow(clippy::too_many_arguments)]
    fn from_cached_views_with_shader_layout(
        image: vk::Image,
        format: vk::Format,
        width: u32,
        height: u32,
        base_array_layer: u32,
        views: NativeVulkanDecodedVideoPlaneViews,
        source_layout: vk::ImageLayout,
        shader_layout: vk::ImageLayout,
        source_access: vk::AccessFlags,
    ) -> Result<Self, NativeVulkanError> {
        if width == 0 || height == 0 || !width.is_multiple_of(2) || !height.is_multiple_of(2) {
            return Err(NativeVulkanError::Video(format!(
                "decoded {} texture requires non-zero even dimensions, got {width}x{height}",
                native_vulkan_format_label(format)
            )));
        }
        native_vulkan_decoded_video_plane_formats(format)?;
        Ok(Self {
            image,
            width,
            height,
            base_array_layer,
            y_view: views.y_view,
            uv_view: views.uv_view,
            owns_views: false,
            source_layout,
            shader_layout,
            source_access,
        })
    }

    fn shader_read_barriers(&self) -> Vec<vk::ImageMemoryBarrier<'static>> {
        if self.source_layout == self.shader_layout
            && self.source_access == vk::AccessFlags::SHADER_READ
        {
            return Vec::new();
        }
        vec![
            self.shader_read_barrier(vk::ImageAspectFlags::PLANE_0),
            self.shader_read_barrier(vk::ImageAspectFlags::PLANE_1),
        ]
    }

    fn shader_read_barrier(
        &self,
        aspect_mask: vk::ImageAspectFlags,
    ) -> vk::ImageMemoryBarrier<'static> {
        vk::ImageMemoryBarrier::default()
            .old_layout(self.source_layout)
            .new_layout(self.shader_layout)
            .src_queue_family_index(vk::QUEUE_FAMILY_IGNORED)
            .dst_queue_family_index(vk::QUEUE_FAMILY_IGNORED)
            .image(self.image)
            .subresource_range(vk::ImageSubresourceRange {
                aspect_mask,
                base_mip_level: 0,
                level_count: 1,
                base_array_layer: self.base_array_layer,
                layer_count: 1,
            })
            .src_access_mask(self.source_access)
            .dst_access_mask(vk::AccessFlags::SHADER_READ)
    }

    fn clone_cached_views(&self) -> Result<Self, NativeVulkanError> {
        if self.owns_views {
            return Err(NativeVulkanError::Video(
                "present-frame queue cannot clone an owning decoded texture".to_owned(),
            ));
        }
        Ok(Self {
            image: self.image,
            width: self.width,
            height: self.height,
            base_array_layer: self.base_array_layer,
            y_view: self.y_view,
            uv_view: self.uv_view,
            owns_views: false,
            source_layout: self.source_layout,
            shader_layout: self.shader_layout,
            source_access: self.source_access,
        })
    }

    fn destroy(self, device: &ash::Device) {
        if self.owns_views {
            unsafe {
                device.destroy_image_view(self.uv_view, None);
                device.destroy_image_view(self.y_view, None);
            }
        }
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
#[derive(Debug, Clone, Copy)]
struct NativeVulkanDecodedVideoPlaneViews {
    y_view: vk::ImageView,
    uv_view: vk::ImageView,
}

#[cfg(feature = "native-vulkan-gst-video")]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct NativeVulkanDecodedVideoPlaneFormats {
    y_view_format: vk::Format,
    uv_view_format: vk::Format,
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_decoded_video_plane_formats(
    format: vk::Format,
) -> Result<NativeVulkanDecodedVideoPlaneFormats, NativeVulkanError> {
    match format {
        vk::Format::G8_B8R8_2PLANE_420_UNORM => Ok(NativeVulkanDecodedVideoPlaneFormats {
            y_view_format: vk::Format::R8_UNORM,
            uv_view_format: vk::Format::R8G8_UNORM,
        }),
        vk::Format::G10X6_B10X6R10X6_2PLANE_420_UNORM_3PACK16 => {
            Ok(NativeVulkanDecodedVideoPlaneFormats {
                y_view_format: vk::Format::R16_UNORM,
                uv_view_format: vk::Format::R16G16_UNORM,
            })
        }
        _ => Err(NativeVulkanError::Video(format!(
            "{} decoded video plane sampling is not implemented",
            native_vulkan_format_label(format)
        ))),
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_create_decoded_video_plane_view_cache(
    device: &ash::Device,
    image: vk::Image,
    format: vk::Format,
    array_layers: u32,
) -> Result<Vec<NativeVulkanDecodedVideoPlaneViews>, NativeVulkanError> {
    let plane_formats = native_vulkan_decoded_video_plane_formats(format)?;
    let mut views = Vec::with_capacity(array_layers as usize);
    for base_array_layer in 0..array_layers {
        let y_view = native_vulkan_create_decoded_video_plane_view(
            device,
            image,
            vk::ImageAspectFlags::PLANE_0,
            plane_formats.y_view_format,
            base_array_layer,
            "y",
        )?;
        let uv_view = match native_vulkan_create_decoded_video_plane_view(
            device,
            image,
            vk::ImageAspectFlags::PLANE_1,
            plane_formats.uv_view_format,
            base_array_layer,
            "uv",
        ) {
            Ok(view) => view,
            Err(err) => {
                unsafe {
                    device.destroy_image_view(y_view, None);
                }
                native_vulkan_destroy_decoded_video_plane_view_cache(device, views);
                return Err(err);
            }
        };
        views.push(NativeVulkanDecodedVideoPlaneViews { y_view, uv_view });
    }
    Ok(views)
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_destroy_decoded_video_plane_view_cache(
    device: &ash::Device,
    views: Vec<NativeVulkanDecodedVideoPlaneViews>,
) {
    unsafe {
        for view in views {
            device.destroy_image_view(view.uv_view, None);
            device.destroy_image_view(view.y_view, None);
        }
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
struct NativeVulkanDecodedVideoDisplayImage {
    image: vk::Image,
    memory: vk::DeviceMemory,
    plane_views: Vec<NativeVulkanDecodedVideoPlaneViews>,
    layouts: Vec<vk::ImageLayout>,
    memory_size: u64,
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_create_decoded_video_display_image(
    device: &ash::Device,
    memory_properties: &vk::PhysicalDeviceMemoryProperties,
    extent: vk::Extent2D,
    format: vk::Format,
    array_layers: u32,
    queue_family_indices: &[u32],
) -> Result<NativeVulkanDecodedVideoDisplayImage, NativeVulkanError> {
    if extent.width == 0 || extent.height == 0 || array_layers == 0 {
        return Err(NativeVulkanError::Video(format!(
            "decoded video display image requires non-zero extent/layers, got {}x{}x{}",
            extent.width, extent.height, array_layers
        )));
    }
    let image_info = vk::ImageCreateInfo::default()
        .flags(vk::ImageCreateFlags::MUTABLE_FORMAT)
        .image_type(vk::ImageType::TYPE_2D)
        .format(format)
        .extent(vk::Extent3D {
            width: extent.width,
            height: extent.height,
            depth: 1,
        })
        .mip_levels(1)
        .array_layers(array_layers)
        .samples(vk::SampleCountFlags::TYPE_1)
        .tiling(vk::ImageTiling::OPTIMAL)
        .usage(vk::ImageUsageFlags::TRANSFER_DST | vk::ImageUsageFlags::SAMPLED)
        .initial_layout(vk::ImageLayout::UNDEFINED);
    let image_info = if queue_family_indices.len() > 1 {
        image_info
            .sharing_mode(vk::SharingMode::CONCURRENT)
            .queue_family_indices(queue_family_indices)
    } else {
        image_info.sharing_mode(vk::SharingMode::EXCLUSIVE)
    };
    let image = unsafe { device.create_image(&image_info, None) }.map_err(|result| {
        NativeVulkanError::Vulkan {
            operation: "vkCreateImage(decoded video display ring)",
            result,
        }
    })?;

    let result = (|| -> Result<NativeVulkanDecodedVideoDisplayImage, NativeVulkanError> {
        let requirements = unsafe { device.get_image_memory_requirements(image) };
        let memory_type_index = native_vulkan_memory_type_index_prefer(
            memory_properties,
            requirements.memory_type_bits,
            vk::MemoryPropertyFlags::DEVICE_LOCAL,
            vk::MemoryPropertyFlags::empty(),
        )
        .ok_or(NativeVulkanError::MissingMemoryType(
            "decoded video display ring",
        ))?;
        let allocation_info = vk::MemoryAllocateInfo::default()
            .allocation_size(requirements.size)
            .memory_type_index(memory_type_index);
        let memory =
            unsafe { device.allocate_memory(&allocation_info, None) }.map_err(|result| {
                NativeVulkanError::Vulkan {
                    operation: "vkAllocateMemory(decoded video display ring)",
                    result,
                }
            })?;
        if let Err(result) = unsafe { device.bind_image_memory(image, memory, 0) } {
            unsafe {
                device.free_memory(memory, None);
            }
            return Err(NativeVulkanError::Vulkan {
                operation: "vkBindImageMemory(decoded video display ring)",
                result,
            });
        }
        let plane_views = match native_vulkan_create_decoded_video_plane_view_cache(
            device,
            image,
            format,
            array_layers,
        ) {
            Ok(views) => views,
            Err(err) => {
                unsafe {
                    device.free_memory(memory, None);
                }
                return Err(err);
            }
        };
        Ok(NativeVulkanDecodedVideoDisplayImage {
            image,
            memory,
            plane_views,
            layouts: vec![vk::ImageLayout::UNDEFINED; array_layers as usize],
            memory_size: requirements.size,
        })
    })();

    if result.is_err() {
        unsafe {
            device.destroy_image(image, None);
        }
    }
    result
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_destroy_decoded_video_display_image(
    device: &ash::Device,
    image: NativeVulkanDecodedVideoDisplayImage,
) {
    native_vulkan_destroy_decoded_video_plane_view_cache(device, image.plane_views);
    unsafe {
        device.free_memory(image.memory, None);
        device.destroy_image(image.image, None);
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_create_decoded_video_plane_view(
    device: &ash::Device,
    image: vk::Image,
    aspect_mask: vk::ImageAspectFlags,
    format: vk::Format,
    base_array_layer: u32,
    label: &'static str,
) -> Result<vk::ImageView, NativeVulkanError> {
    let mut view_usage_info =
        vk::ImageViewUsageCreateInfo::default().usage(vk::ImageUsageFlags::SAMPLED);
    let view_info = vk::ImageViewCreateInfo::default()
        .image(image)
        .view_type(vk::ImageViewType::TYPE_2D)
        .format(format)
        .subresource_range(vk::ImageSubresourceRange {
            aspect_mask,
            base_mip_level: 0,
            level_count: 1,
            base_array_layer,
            layer_count: 1,
        })
        .push_next(&mut view_usage_info);
    unsafe { device.create_image_view(&view_info, None) }.map_err(|result| {
        NativeVulkanError::Vulkan {
            operation: match label {
                "y" => "vkCreateImageView(decoded video y plane)",
                "uv" => "vkCreateImageView(decoded video uv plane)",
                _ => "vkCreateImageView(decoded video plane)",
            },
            result,
        }
    })
}

#[cfg(feature = "native-vulkan-gst-video")]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct NativeVulkanDmabufVideoPlane {
    fd: i32,
    offset: u64,
    stride: u32,
    height: u32,
}

#[cfg(feature = "native-vulkan-gst-video")]
#[derive(Debug)]
struct NativeVulkanDmabufVideoFrame {
    format: NativeVulkanVideoSampleFormat,
    width: u32,
    height: u32,
    fd: i32,
    modifier: u64,
    y: NativeVulkanDmabufVideoPlane,
    uv: NativeVulkanDmabufVideoPlane,
    _owned_fds: Vec<OwnedFd>,
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_dmabuf_modifier_plane_count(
    instance: &ash::Instance,
    physical_device: vk::PhysicalDevice,
    format: vk::Format,
    modifier: u64,
) -> Option<u32> {
    if modifier == DRM_FORMAT_MOD_INVALID {
        return None;
    }

    let mut modifier_list = vk::DrmFormatModifierPropertiesListEXT::default();
    let mut format_properties = vk::FormatProperties2::default().push_next(&mut modifier_list);
    unsafe {
        instance.get_physical_device_format_properties2(
            physical_device,
            format,
            &mut format_properties,
        );
    }
    if modifier_list.drm_format_modifier_count == 0 {
        return None;
    }

    let mut modifiers = vec![
        vk::DrmFormatModifierPropertiesEXT::default();
        modifier_list.drm_format_modifier_count as usize
    ];
    let mut modifier_list = vk::DrmFormatModifierPropertiesListEXT::default()
        .drm_format_modifier_properties(&mut modifiers);
    let mut format_properties = vk::FormatProperties2::default().push_next(&mut modifier_list);
    unsafe {
        instance.get_physical_device_format_properties2(
            physical_device,
            format,
            &mut format_properties,
        );
    }

    modifiers
        .iter()
        .find(|properties| properties.drm_format_modifier == modifier)
        .map(|properties| properties.drm_format_modifier_plane_count)
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_dmabuf_import_snapshot(
    frame: &NativeVulkanDmabufVideoFrame,
    source: &'static str,
    driver_modifier_plane_count: Option<u32>,
) -> NativeVulkanDmabufImportSnapshot {
    NativeVulkanDmabufImportSnapshot {
        source: source.to_owned(),
        format: frame.format.label(),
        drm_fourcc: frame.format.drm_format(),
        drm_fourcc_hex: format!("0x{:08x}", frame.format.drm_format()),
        modifier: frame.modifier,
        modifier_hex: format!("0x{:016x}", frame.modifier),
        available_plane_count: 2,
        drm_object_count: if frame.y.fd == frame.uv.fd { 1 } else { 2 },
        y_uv_same_fd: frame.y.fd == frame.uv.fd,
        driver_modifier_plane_count,
        y_offset: frame.y.offset,
        y_stride: frame.y.stride,
        uv_offset: frame.uv.offset,
        uv_stride: frame.uv.stride,
        image_memory_type_bits: None,
        image_memory_type_bits_hex: None,
        fd_memory_type_bits: None,
        fd_memory_type_bits_hex: None,
        compatible_memory_type_bits: None,
        compatible_memory_type_bits_hex: None,
        selected_memory_type_index: None,
        memory_allocation_size: None,
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct NativeVulkanDmabufImportMemoryContract {
    image_memory_type_bits: u32,
    fd_memory_type_bits: u32,
    compatible_memory_type_bits: u32,
    selected_memory_type_index: u32,
    memory_allocation_size: u64,
}

#[cfg(feature = "native-vulkan-gst-video")]
impl NativeVulkanDmabufImportSnapshot {
    fn apply_memory_contract(&mut self, contract: NativeVulkanDmabufImportMemoryContract) {
        self.image_memory_type_bits = Some(contract.image_memory_type_bits);
        self.image_memory_type_bits_hex =
            Some(format!("0x{:08x}", contract.image_memory_type_bits));
        self.fd_memory_type_bits = Some(contract.fd_memory_type_bits);
        self.fd_memory_type_bits_hex = Some(format!("0x{:08x}", contract.fd_memory_type_bits));
        self.compatible_memory_type_bits = Some(contract.compatible_memory_type_bits);
        self.compatible_memory_type_bits_hex =
            Some(format!("0x{:08x}", contract.compatible_memory_type_bits));
        self.selected_memory_type_index = Some(contract.selected_memory_type_index);
        self.memory_allocation_size = Some(contract.memory_allocation_size);
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
struct NativeVulkanDmabufVideoTexture {
    width: u32,
    height: u32,
    image: vk::Image,
    memory: vk::DeviceMemory,
    y_view: vk::ImageView,
    uv_view: vk::ImageView,
}

#[cfg(feature = "native-vulkan-gst-video")]
impl NativeVulkanDmabufVideoTexture {
    #[allow(clippy::too_many_arguments)]
    fn new(
        instance: &ash::Instance,
        physical_device: vk::PhysicalDevice,
        _queue: vk::Queue,
        _command_pool: vk::CommandPool,
        device: &ash::Device,
        _queue_family_index: u32,
        frame: &NativeVulkanDmabufVideoFrame,
        driver_modifier_plane_count: Option<u32>,
    ) -> Result<(Self, NativeVulkanDmabufImportMemoryContract), NativeVulkanError> {
        if frame.width == 0 || frame.height == 0 {
            return Err(NativeVulkanError::Video(
                "native Vulkan DMABuf video frame has zero dimension".to_owned(),
            ));
        }
        if frame.width % 2 != 0 || frame.height % 2 != 0 {
            return Err(NativeVulkanError::Video(format!(
                "native Vulkan DMABuf video dimensions must be even, got {}x{}",
                frame.width, frame.height
            )));
        }
        if frame.fd < 0 || frame.y.fd != frame.fd || frame.uv.fd != frame.fd {
            return Err(NativeVulkanError::Video(
                "native Vulkan DMABuf importer currently requires a single fd two-plane YUV420 frame"
                    .to_owned(),
            ));
        }

        let plane_layouts = [
            native_vulkan_dmabuf_plane_layout(frame.y),
            native_vulkan_dmabuf_plane_layout(frame.uv),
        ];
        if let Some(driver_modifier_plane_count) = driver_modifier_plane_count
            && driver_modifier_plane_count as usize != plane_layouts.len()
        {
            return Err(NativeVulkanError::Video(format!(
                "native Vulkan DMABuf importer exposes {} Y/UV plane layouts, but driver expects {driver_modifier_plane_count} plane layouts for modifier 0x{:016x}",
                plane_layouts.len(),
                frame.modifier
            )));
        }
        let handle_type = vk::ExternalMemoryHandleTypeFlags::DMA_BUF_EXT;
        let mut external_image_info =
            vk::ExternalMemoryImageCreateInfo::default().handle_types(handle_type);
        let mut drm_modifier_info = vk::ImageDrmFormatModifierExplicitCreateInfoEXT::default()
            .drm_format_modifier(frame.modifier)
            .plane_layouts(&plane_layouts);
        let image_info = vk::ImageCreateInfo::default()
            .flags(vk::ImageCreateFlags::MUTABLE_FORMAT)
            .image_type(vk::ImageType::TYPE_2D)
            .format(frame.format.vulkan_image_format())
            .extent(vk::Extent3D {
                width: frame.width,
                height: frame.height,
                depth: 1,
            })
            .mip_levels(1)
            .array_layers(1)
            .samples(vk::SampleCountFlags::TYPE_1)
            .tiling(vk::ImageTiling::DRM_FORMAT_MODIFIER_EXT)
            .usage(vk::ImageUsageFlags::SAMPLED)
            .sharing_mode(vk::SharingMode::EXCLUSIVE)
            .initial_layout(vk::ImageLayout::UNDEFINED)
            .push_next(&mut external_image_info)
            .push_next(&mut drm_modifier_info);
        let image = unsafe { device.create_image(&image_info, None) }.map_err(|result| {
            NativeVulkanError::Vulkan {
                operation: "vkCreateImage(video DMABuf image)",
                result,
            }
        })?;

        let requirements = unsafe { device.get_image_memory_requirements(image) };
        let external_memory_fd = ash::khr::external_memory_fd::Device::new(instance, device);
        let mut fd_properties = vk::MemoryFdPropertiesKHR::default();
        unsafe {
            external_memory_fd
                .get_memory_fd_properties(handle_type, frame.fd, &mut fd_properties)
                .map_err(|result| {
                    device.destroy_image(image, None);
                    NativeVulkanError::Vulkan {
                        operation: "vkGetMemoryFdPropertiesKHR(video DMABuf)",
                        result,
                    }
                })?;
        }
        let memory_type_bits = requirements.memory_type_bits & fd_properties.memory_type_bits;
        if memory_type_bits == 0 {
            unsafe {
                device.destroy_image(image, None);
            }
            return Err(NativeVulkanError::Video(format!(
                "native Vulkan DMABuf import has zero compatible memory_type_bits: image=0x{:08x} fd=0x{:08x}",
                requirements.memory_type_bits, fd_properties.memory_type_bits
            )));
        }
        let memory_properties =
            unsafe { instance.get_physical_device_memory_properties(physical_device) };
        let memory_type_index = native_vulkan_memory_type_index_prefer(
            &memory_properties,
            memory_type_bits,
            vk::MemoryPropertyFlags::DEVICE_LOCAL,
            vk::MemoryPropertyFlags::empty(),
        )
        .ok_or_else(|| {
            unsafe {
                device.destroy_image(image, None);
            }
            NativeVulkanError::MissingMemoryType("video DMABuf image")
        })?;

        let duplicated_fd = native_vulkan_dup_fd(frame.fd).map_err(|err| {
            unsafe {
                device.destroy_image(image, None);
            }
            err
        })?;
        let mut import_info = vk::ImportMemoryFdInfoKHR::default()
            .handle_type(handle_type)
            .fd(duplicated_fd.as_raw_fd());
        let mut dedicated_info = vk::MemoryDedicatedAllocateInfo::default().image(image);
        let allocate_info = vk::MemoryAllocateInfo::default()
            .allocation_size(requirements.size)
            .memory_type_index(memory_type_index)
            .push_next(&mut dedicated_info)
            .push_next(&mut import_info);
        let memory = match unsafe { device.allocate_memory(&allocate_info, None) } {
            Ok(memory) => {
                let _ = duplicated_fd.into_raw_fd();
                memory
            }
            Err(result) => {
                unsafe {
                    device.destroy_image(image, None);
                }
                return Err(NativeVulkanError::Vulkan {
                    operation: "vkAllocateMemory(video DMABuf image)",
                    result,
                });
            }
        };
        if let Err(result) = unsafe { device.bind_image_memory(image, memory, 0) } {
            unsafe {
                device.free_memory(memory, None);
                device.destroy_image(image, None);
            }
            return Err(NativeVulkanError::Vulkan {
                operation: "vkBindImageMemory(video DMABuf image)",
                result,
            });
        }

        let y_view = match native_vulkan_create_dmabuf_plane_view(
            device,
            image,
            vk::ImageAspectFlags::PLANE_0,
            frame.format.y_view_format(),
            "y",
        ) {
            Ok(view) => view,
            Err(err) => {
                unsafe {
                    device.free_memory(memory, None);
                    device.destroy_image(image, None);
                }
                return Err(err);
            }
        };
        let uv_view = match native_vulkan_create_dmabuf_plane_view(
            device,
            image,
            vk::ImageAspectFlags::PLANE_1,
            frame.format.uv_view_format(),
            "uv",
        ) {
            Ok(view) => view,
            Err(err) => {
                unsafe {
                    device.destroy_image_view(y_view, None);
                    device.free_memory(memory, None);
                    device.destroy_image(image, None);
                }
                return Err(err);
            }
        };

        Ok((
            Self {
                width: frame.width,
                height: frame.height,
                image,
                memory,
                y_view,
                uv_view,
            },
            NativeVulkanDmabufImportMemoryContract {
                image_memory_type_bits: requirements.memory_type_bits,
                fd_memory_type_bits: fd_properties.memory_type_bits,
                compatible_memory_type_bits: memory_type_bits,
                selected_memory_type_index: memory_type_index,
                memory_allocation_size: requirements.size,
            },
        ))
    }

    fn shader_read_barriers(&self) -> Vec<vk::ImageMemoryBarrier<'static>> {
        vec![
            native_vulkan_dmabuf_shader_read_barrier(self.image, vk::ImageAspectFlags::PLANE_0),
            native_vulkan_dmabuf_shader_read_barrier(self.image, vk::ImageAspectFlags::PLANE_1),
        ]
    }

    fn destroy(self, device: &ash::Device) {
        unsafe {
            device.destroy_image_view(self.uv_view, None);
            device.destroy_image_view(self.y_view, None);
            device.free_memory(self.memory, None);
            device.destroy_image(self.image, None);
        }
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_dmabuf_plane_layout(plane: NativeVulkanDmabufVideoPlane) -> vk::SubresourceLayout {
    vk::SubresourceLayout {
        offset: plane.offset,
        size: u64::from(plane.stride) * u64::from(plane.height),
        row_pitch: u64::from(plane.stride),
        array_pitch: 0,
        depth_pitch: 0,
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_dmabuf_shader_read_barrier(
    image: vk::Image,
    aspect_mask: vk::ImageAspectFlags,
) -> vk::ImageMemoryBarrier<'static> {
    vk::ImageMemoryBarrier::default()
        .old_layout(vk::ImageLayout::GENERAL)
        .new_layout(vk::ImageLayout::GENERAL)
        .src_queue_family_index(vk::QUEUE_FAMILY_IGNORED)
        .dst_queue_family_index(vk::QUEUE_FAMILY_IGNORED)
        .image(image)
        .subresource_range(vk::ImageSubresourceRange {
            aspect_mask,
            base_mip_level: 0,
            level_count: 1,
            base_array_layer: 0,
            layer_count: 1,
        })
        .src_access_mask(vk::AccessFlags::MEMORY_WRITE)
        .dst_access_mask(vk::AccessFlags::SHADER_READ)
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_create_dmabuf_plane_view(
    device: &ash::Device,
    image: vk::Image,
    aspect_mask: vk::ImageAspectFlags,
    format: vk::Format,
    label: &'static str,
) -> Result<vk::ImageView, NativeVulkanError> {
    let view_info = vk::ImageViewCreateInfo::default()
        .image(image)
        .view_type(vk::ImageViewType::TYPE_2D)
        .format(format)
        .subresource_range(vk::ImageSubresourceRange {
            aspect_mask,
            base_mip_level: 0,
            level_count: 1,
            base_array_layer: 0,
            layer_count: 1,
        });
    unsafe { device.create_image_view(&view_info, None) }.map_err(|result| {
        NativeVulkanError::Vulkan {
            operation: match label {
                "y" => "vkCreateImageView(video DMABuf y plane)",
                "uv" => "vkCreateImageView(video DMABuf uv plane)",
                _ => "vkCreateImageView(video DMABuf plane)",
            },
            result,
        }
    })
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_dup_fd(fd: i32) -> Result<OwnedFd, NativeVulkanError> {
    let borrowed = unsafe { BorrowedFd::borrow_raw(fd) };
    borrowed.try_clone_to_owned().map_err(|err| {
        NativeVulkanError::Video(format!("native Vulkan DMABuf dup fd failed: {}", err))
    })
}

#[cfg(feature = "native-vulkan-gst-video")]
struct NativeVulkanCudaVideoTexture {
    cuda_context: *mut NativeVulkanGstCudaContext,
    format: NativeVulkanVideoSampleFormat,
    width: u32,
    height: u32,
    cuda_stream: NativeVulkanCudaStream,
    y: NativeVulkanCudaVideoPlane,
    uv: NativeVulkanCudaVideoPlane,
}

#[cfg(feature = "native-vulkan-gst-video")]
impl NativeVulkanCudaVideoTexture {
    fn new(
        instance: &ash::Instance,
        physical_device: vk::PhysicalDevice,
        queue: vk::Queue,
        command_pool: vk::CommandPool,
        device: &ash::Device,
        queue_family_index: u32,
        cuda_context: *mut NativeVulkanGstCudaContext,
        width: u32,
        height: u32,
        format: NativeVulkanVideoSampleFormat,
    ) -> Result<Self, NativeVulkanError> {
        if width == 0 || height == 0 {
            return Err(NativeVulkanError::Video(
                "native Vulkan CUDA video frame has zero dimension".to_owned(),
            ));
        }
        if width % 2 != 0 || height % 2 != 0 {
            return Err(NativeVulkanError::Video(format!(
                "native Vulkan CUDA video dimensions must be even, got {width}x{height}"
            )));
        }
        if cuda_context.is_null() {
            return Err(NativeVulkanError::Video(
                "native Vulkan CUDA video sample has null GstCudaContext".to_owned(),
            ));
        }
        let _guard = NativeVulkanGstCudaContextPushGuard::new(cuda_context)?;
        let cuda_stream = NativeVulkanCudaStream::new()?;
        let y = NativeVulkanCudaVideoPlane::new(
            instance,
            physical_device,
            queue,
            command_pool,
            device,
            queue_family_index,
            width,
            height,
            format.y_view_format(),
            1,
            format.bytes_per_component(),
            format.cuda_array_format(),
            "y",
        )?;
        let uv = match NativeVulkanCudaVideoPlane::new(
            instance,
            physical_device,
            queue,
            command_pool,
            device,
            queue_family_index,
            width / 2,
            height / 2,
            format.uv_view_format(),
            2,
            format.bytes_per_component(),
            format.cuda_array_format(),
            "uv",
        ) {
            Ok(plane) => plane,
            Err(err) => {
                y.destroy(device);
                return Err(err);
            }
        };
        Ok(Self {
            cuda_context,
            format,
            width,
            height,
            cuda_stream,
            y,
            uv,
        })
    }

    fn matches(
        &self,
        cuda_context: *mut NativeVulkanGstCudaContext,
        width: u32,
        height: u32,
        format: NativeVulkanVideoSampleFormat,
    ) -> bool {
        self.cuda_context == cuda_context
            && self.width == width
            && self.height == height
            && self.format == format
    }

    fn copy_sample(
        &mut self,
        buffer: &gst::BufferRef,
        meta: &NativeVulkanGstSystemNv12Meta,
    ) -> Result<(), NativeVulkanError> {
        let _guard = NativeVulkanGstCudaContextPushGuard::new(self.cuda_context)?;
        let y_map = native_vulkan_copy_gst_cuda_plane_to_vulkan_image(
            buffer,
            0,
            meta.y.offset,
            meta.y.stride,
            meta.y.row_bytes,
            meta.y.height,
            self.cuda_context,
            self.cuda_stream.handle,
            &self.y,
            "y",
        )?;
        let uv_map = match native_vulkan_copy_gst_cuda_plane_to_vulkan_image(
            buffer,
            1,
            meta.uv.offset,
            meta.uv.stride,
            meta.uv.row_bytes,
            meta.uv.height,
            self.cuda_context,
            self.cuda_stream.handle,
            &self.uv,
            "uv",
        ) {
            Ok(map) => map,
            Err(err) => {
                let sync_result = native_vulkan_cuda_result(
                    unsafe { CuStreamSynchronize(self.cuda_stream.handle) },
                    "native Vulkan CUDA synchronize after failed uv copy",
                );
                drop(y_map);
                sync_result?;
                return Err(err);
            }
        };
        let sync_result = native_vulkan_cuda_result(
            unsafe { CuStreamSynchronize(self.cuda_stream.handle) },
            "native Vulkan CUDA synchronize copy stream",
        );
        drop(uv_map);
        drop(y_map);
        sync_result?;
        Ok(())
    }

    fn shader_read_barriers(&self) -> Vec<vk::ImageMemoryBarrier<'static>> {
        vec![self.y.shader_read_barrier(), self.uv.shader_read_barrier()]
    }

    fn destroy(self, device: &ash::Device) {
        let _ = unsafe { CuStreamSynchronize(self.cuda_stream.handle) };
        self.uv.destroy(device);
        self.y.destroy(device);
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
struct NativeVulkanCudaVideoPlane {
    cuda_external_memory: NativeVulkanCudaExternalImageMemory,
    image: vk::Image,
    memory: vk::DeviceMemory,
    view: vk::ImageView,
    width: u32,
    height: u32,
    channels: u32,
    bytes_per_channel: u32,
}

#[cfg(feature = "native-vulkan-gst-video")]
impl NativeVulkanCudaVideoPlane {
    #[allow(clippy::too_many_arguments)]
    fn new(
        instance: &ash::Instance,
        physical_device: vk::PhysicalDevice,
        queue: vk::Queue,
        command_pool: vk::CommandPool,
        device: &ash::Device,
        queue_family_index: u32,
        width: u32,
        height: u32,
        format: vk::Format,
        channels: u32,
        bytes_per_channel: u32,
        cuda_array_format: u32,
        label: &'static str,
    ) -> Result<Self, NativeVulkanError> {
        let handle_type = vk::ExternalMemoryHandleTypeFlags::OPAQUE_FD;
        let mut external_image_info =
            vk::ExternalMemoryImageCreateInfo::default().handle_types(handle_type);
        let image_info = vk::ImageCreateInfo::default()
            .image_type(vk::ImageType::TYPE_2D)
            .format(format)
            .extent(vk::Extent3D {
                width,
                height,
                depth: 1,
            })
            .mip_levels(1)
            .array_layers(1)
            .samples(vk::SampleCountFlags::TYPE_1)
            .tiling(vk::ImageTiling::OPTIMAL)
            .usage(vk::ImageUsageFlags::SAMPLED)
            .sharing_mode(vk::SharingMode::EXCLUSIVE)
            .initial_layout(vk::ImageLayout::UNDEFINED)
            .push_next(&mut external_image_info);
        let image = unsafe { device.create_image(&image_info, None) }.map_err(|result| {
            NativeVulkanError::Vulkan {
                operation: "vkCreateImage(video CUDA plane)",
                result,
            }
        })?;
        let requirements = unsafe { device.get_image_memory_requirements(image) };
        let memory_properties =
            unsafe { instance.get_physical_device_memory_properties(physical_device) };
        let memory_type_index = native_vulkan_memory_type_index_prefer(
            &memory_properties,
            requirements.memory_type_bits,
            vk::MemoryPropertyFlags::DEVICE_LOCAL,
            vk::MemoryPropertyFlags::empty(),
        )
        .ok_or_else(|| {
            unsafe {
                device.destroy_image(image, None);
            }
            NativeVulkanError::MissingMemoryType("video CUDA external image")
        })?;
        let mut export_info = vk::ExportMemoryAllocateInfo::default().handle_types(handle_type);
        let mut dedicated_info = vk::MemoryDedicatedAllocateInfo::default().image(image);
        let allocate_info = vk::MemoryAllocateInfo::default()
            .allocation_size(requirements.size)
            .memory_type_index(memory_type_index)
            .push_next(&mut dedicated_info)
            .push_next(&mut export_info);
        let memory = match unsafe { device.allocate_memory(&allocate_info, None) } {
            Ok(memory) => memory,
            Err(result) => {
                unsafe {
                    device.destroy_image(image, None);
                }
                return Err(NativeVulkanError::Vulkan {
                    operation: "vkAllocateMemory(video CUDA plane)",
                    result,
                });
            }
        };
        if let Err(result) = unsafe { device.bind_image_memory(image, memory, 0) } {
            unsafe {
                device.free_memory(memory, None);
                device.destroy_image(image, None);
            }
            return Err(NativeVulkanError::Vulkan {
                operation: "vkBindImageMemory(video CUDA plane)",
                result,
            });
        }
        let view_info = vk::ImageViewCreateInfo::default()
            .image(image)
            .view_type(vk::ImageViewType::TYPE_2D)
            .format(format)
            .subresource_range(native_vulkan_color_subresource_range());
        let view = match unsafe { device.create_image_view(&view_info, None) } {
            Ok(view) => view,
            Err(result) => {
                unsafe {
                    device.free_memory(memory, None);
                    device.destroy_image(image, None);
                }
                return Err(NativeVulkanError::Vulkan {
                    operation: "vkCreateImageView(video CUDA plane)",
                    result,
                });
            }
        };
        let external_memory_fd = ash::khr::external_memory_fd::Device::new(instance, device);
        let fd_info = vk::MemoryGetFdInfoKHR::default()
            .memory(memory)
            .handle_type(handle_type);
        let fd = match unsafe { external_memory_fd.get_memory_fd(&fd_info) } {
            Ok(fd) => fd,
            Err(result) => {
                unsafe {
                    device.destroy_image_view(view, None);
                    device.free_memory(memory, None);
                    device.destroy_image(image, None);
                }
                return Err(NativeVulkanError::Vulkan {
                    operation: "vkGetMemoryFdKHR(video CUDA plane)",
                    result,
                });
            }
        };
        let cuda_external_memory = match NativeVulkanCudaExternalImageMemory::import_opaque_fd(
            fd,
            requirements.size,
            width,
            height,
            channels,
            cuda_array_format,
            label,
        ) {
            Ok(memory) => memory,
            Err(err) => {
                unsafe {
                    device.destroy_image_view(view, None);
                    device.free_memory(memory, None);
                    device.destroy_image(image, None);
                }
                return Err(err);
            }
        };
        if let Err(err) = native_vulkan_transition_image_to_general(
            device,
            queue,
            command_pool,
            image,
            queue_family_index,
        ) {
            unsafe {
                device.destroy_image_view(view, None);
                device.free_memory(memory, None);
                device.destroy_image(image, None);
            }
            drop(cuda_external_memory);
            return Err(err);
        }

        Ok(Self {
            cuda_external_memory,
            image,
            memory,
            view,
            width,
            height,
            channels,
            bytes_per_channel,
        })
    }

    fn shader_read_barrier(&self) -> vk::ImageMemoryBarrier<'static> {
        vk::ImageMemoryBarrier::default()
            .old_layout(vk::ImageLayout::GENERAL)
            .new_layout(vk::ImageLayout::GENERAL)
            .src_queue_family_index(vk::QUEUE_FAMILY_IGNORED)
            .dst_queue_family_index(vk::QUEUE_FAMILY_IGNORED)
            .image(self.image)
            .subresource_range(native_vulkan_color_subresource_range())
            .src_access_mask(vk::AccessFlags::MEMORY_WRITE)
            .dst_access_mask(vk::AccessFlags::SHADER_READ)
    }

    fn destroy(self, device: &ash::Device) {
        drop(self.cuda_external_memory);
        unsafe {
            device.destroy_image_view(self.view, None);
            device.free_memory(self.memory, None);
            device.destroy_image(self.image, None);
        }
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_transition_image_to_general(
    device: &ash::Device,
    queue: vk::Queue,
    command_pool: vk::CommandPool,
    image: vk::Image,
    queue_family_index: u32,
) -> Result<(), NativeVulkanError> {
    let allocate_info = vk::CommandBufferAllocateInfo::default()
        .command_pool(command_pool)
        .level(vk::CommandBufferLevel::PRIMARY)
        .command_buffer_count(1);
    let command_buffer =
        unsafe { device.allocate_command_buffers(&allocate_info) }.map_err(|result| {
            NativeVulkanError::Vulkan {
                operation: "vkAllocateCommandBuffers(video image transition)",
                result,
            }
        })?[0];
    let result = unsafe {
        let begin_info = vk::CommandBufferBeginInfo::default()
            .flags(vk::CommandBufferUsageFlags::ONE_TIME_SUBMIT);
        device
            .begin_command_buffer(command_buffer, &begin_info)
            .map_err(|result| NativeVulkanError::Vulkan {
                operation: "vkBeginCommandBuffer(video image transition)",
                result,
            })?;
        let barrier = vk::ImageMemoryBarrier::default()
            .old_layout(vk::ImageLayout::UNDEFINED)
            .new_layout(vk::ImageLayout::GENERAL)
            .src_queue_family_index(vk::QUEUE_FAMILY_IGNORED)
            .dst_queue_family_index(vk::QUEUE_FAMILY_IGNORED)
            .image(image)
            .subresource_range(native_vulkan_color_subresource_range())
            .src_access_mask(vk::AccessFlags::empty())
            .dst_access_mask(vk::AccessFlags::SHADER_READ);
        device.cmd_pipeline_barrier(
            command_buffer,
            vk::PipelineStageFlags::TOP_OF_PIPE,
            vk::PipelineStageFlags::FRAGMENT_SHADER,
            vk::DependencyFlags::empty(),
            &[],
            &[],
            &[barrier],
        );
        device
            .end_command_buffer(command_buffer)
            .map_err(|result| NativeVulkanError::Vulkan {
                operation: "vkEndCommandBuffer(video image transition)",
                result,
            })?;
        let command_buffers = [command_buffer];
        let submit_info = vk::SubmitInfo::default().command_buffers(&command_buffers);
        device
            .queue_submit(queue, &[submit_info], vk::Fence::null())
            .map_err(|result| NativeVulkanError::Vulkan {
                operation: "vkQueueSubmit(video image transition)",
                result,
            })?;
        device
            .queue_wait_idle(queue)
            .map_err(|result| NativeVulkanError::Vulkan {
                operation: "vkQueueWaitIdle(video image transition)",
                result,
            })
    };
    unsafe {
        device.free_command_buffers(command_pool, &[command_buffer]);
    }
    let _ = queue_family_index;
    result
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_memory_type_index_prefer(
    memory_properties: &vk::PhysicalDeviceMemoryProperties,
    memory_type_bits: u32,
    preferred: vk::MemoryPropertyFlags,
    required: vk::MemoryPropertyFlags,
) -> Option<u32> {
    let mut fallback = None;
    for (index, memory_type) in memory_properties.memory_types
        [..memory_properties.memory_type_count as usize]
        .iter()
        .enumerate()
    {
        let supported = (memory_type_bits & (1 << index)) != 0;
        if !supported || !memory_type.property_flags.contains(required) {
            continue;
        }
        let index = index as u32;
        if memory_type.property_flags.contains(preferred) {
            return Some(index);
        }
        fallback.get_or_insert(index);
    }
    fallback
}

#[cfg(feature = "native-vulkan-gst-video")]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum NativeVulkanVideoSampleFormat {
    Nv12,
    P010,
}

#[cfg(feature = "native-vulkan-gst-video")]
impl NativeVulkanVideoSampleFormat {
    fn from_caps_format(format: &str) -> Option<Self> {
        match format {
            "NV12" => Some(Self::Nv12),
            "P010_10LE" | "P010" => Some(Self::P010),
            _ => None,
        }
    }

    fn label(self) -> &'static str {
        match self {
            Self::Nv12 => "NV12",
            Self::P010 => "P010_10LE",
        }
    }

    fn vulkan_image_format(self) -> vk::Format {
        match self {
            Self::Nv12 => vk::Format::G8_B8R8_2PLANE_420_UNORM,
            Self::P010 => vk::Format::G10X6_B10X6R10X6_2PLANE_420_UNORM_3PACK16,
        }
    }

    fn y_view_format(self) -> vk::Format {
        match self {
            Self::Nv12 => vk::Format::R8_UNORM,
            Self::P010 => vk::Format::R16_UNORM,
        }
    }

    fn uv_view_format(self) -> vk::Format {
        match self {
            Self::Nv12 => vk::Format::R8G8_UNORM,
            Self::P010 => vk::Format::R16G16_UNORM,
        }
    }

    fn bytes_per_component(self) -> u32 {
        match self {
            Self::Nv12 => 1,
            Self::P010 => 2,
        }
    }

    fn cuda_array_format(self) -> u32 {
        match self {
            Self::Nv12 => CUDA_ARRAY_FORMAT_UNSIGNED_INT8,
            Self::P010 => CUDA_ARRAY_FORMAT_UNSIGNED_INT16,
        }
    }

    fn drm_format(self) -> u32 {
        match self {
            Self::Nv12 => DRM_FORMAT_NV12,
            Self::P010 => DRM_FORMAT_P010,
        }
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct NativeVulkanGstSystemNv12Plane {
    offset: usize,
    stride: u32,
    height: u32,
    row_bytes: u32,
}

#[cfg(feature = "native-vulkan-gst-video")]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct NativeVulkanGstSystemNv12Meta {
    format: NativeVulkanVideoSampleFormat,
    width: u32,
    height: u32,
    y: NativeVulkanGstSystemNv12Plane,
    uv: NativeVulkanGstSystemNv12Plane,
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_gst_system_yuv420_meta(
    sample: &gst::Sample,
    buffer: &gst::BufferRef,
) -> Result<NativeVulkanGstSystemNv12Meta, NativeVulkanError> {
    let meta = match native_vulkan_gst_yuv420_meta_from_video_meta(sample.caps(), buffer) {
        Ok(meta) => meta,
        Err(meta_err) => native_vulkan_gst_yuv420_meta_from_caps(sample)
            .map_err(|caps_err| NativeVulkanError::Video(format!("{meta_err};{caps_err}")))?,
    };
    Ok(meta)
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_gst_yuv420_meta_from_video_meta(
    caps: Option<&gst::CapsRef>,
    buffer: &gst::BufferRef,
) -> Result<NativeVulkanGstSystemNv12Meta, String> {
    let meta = buffer
        .meta::<gst_video::VideoMeta>()
        .ok_or_else(|| "appsink buffer has no GstVideoMeta".to_owned())?;
    let caps_format = caps
        .and_then(|caps| caps.structure(0))
        .and_then(|structure| structure.get::<String>("format").ok())
        .unwrap_or_else(|| meta.format().to_str().to_string());
    let format = NativeVulkanVideoSampleFormat::from_caps_format(&caps_format)
        .ok_or_else(|| format!("expected NV12 or P010 appsink frame, got {caps_format}"))?;
    let width = meta.width();
    let height = meta.height();
    if width == 0 || height == 0 {
        return Err("NV12 frame has zero dimension".to_owned());
    }
    if width % 2 != 0 || height % 2 != 0 {
        return Err(format!(
            "{} frame dimensions must be even, got {width}x{height}",
            format.label()
        ));
    }
    if meta.offset().len() < 2 || meta.stride().len() < 2 {
        return Err(format!(
            "{} frame needs 2 planes, got offsets={} strides={}",
            format.label(),
            meta.offset().len(),
            meta.stride().len()
        ));
    }
    let y_stride =
        native_vulkan_positive_stride(format!("{} y", format.label()), meta.stride()[0])?;
    let uv_stride =
        native_vulkan_positive_stride(format!("{} uv", format.label()), meta.stride()[1])?;
    let row_bytes = width
        .checked_mul(format.bytes_per_component())
        .ok_or_else(|| format!("{} row byte width overflow", format.label()))?;
    if y_stride < row_bytes || uv_stride < row_bytes {
        return Err(format!(
            "{} stride too small: y={y_stride} uv={uv_stride} row_bytes={row_bytes}",
            format.label()
        ));
    }
    Ok(NativeVulkanGstSystemNv12Meta {
        format,
        width,
        height,
        y: NativeVulkanGstSystemNv12Plane {
            offset: meta.offset()[0],
            stride: y_stride,
            height,
            row_bytes,
        },
        uv: NativeVulkanGstSystemNv12Plane {
            offset: meta.offset()[1],
            stride: uv_stride,
            height: height / 2,
            row_bytes,
        },
    })
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_gst_yuv420_meta_from_caps(
    sample: &gst::Sample,
) -> Result<NativeVulkanGstSystemNv12Meta, String> {
    let caps = sample
        .caps()
        .ok_or_else(|| "appsink sample has no caps".to_owned())?;
    let structure = caps
        .structure(0)
        .ok_or_else(|| "appsink caps has no structure".to_owned())?;
    let format = structure
        .get::<String>("format")
        .unwrap_or_else(|_| "unknown".to_owned());
    let format = NativeVulkanVideoSampleFormat::from_caps_format(&format)
        .ok_or_else(|| format!("caps fallback expected NV12 or P010, got {format}"))?;
    let width = structure
        .get::<i32>("width")
        .map_err(|_| "appsink caps missing width".to_owned())
        .and_then(|width| {
            u32::try_from(width)
                .ok()
                .filter(|width| *width > 0)
                .ok_or_else(|| "invalid appsink frame width".to_owned())
        })?;
    let height = structure
        .get::<i32>("height")
        .map_err(|_| "appsink caps missing height".to_owned())
        .and_then(|height| {
            u32::try_from(height)
                .ok()
                .filter(|height| *height > 0)
                .ok_or_else(|| "invalid appsink frame height".to_owned())
        })?;
    if width % 2 != 0 || height % 2 != 0 {
        return Err(format!(
            "{} frame dimensions must be even, got {width}x{height}",
            format.label()
        ));
    }
    let row_bytes = width
        .checked_mul(format.bytes_per_component())
        .ok_or_else(|| format!("{} row byte width overflow", format.label()))?;
    let y_size = usize::try_from(u64::from(row_bytes) * u64::from(height))
        .map_err(|_| format!("{} plane offset overflow", format.label()))?;
    Ok(NativeVulkanGstSystemNv12Meta {
        format,
        width,
        height,
        y: NativeVulkanGstSystemNv12Plane {
            offset: 0,
            stride: row_bytes,
            height,
            row_bytes,
        },
        uv: NativeVulkanGstSystemNv12Plane {
            offset: y_size,
            stride: row_bytes,
            height: height / 2,
            row_bytes,
        },
    })
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_positive_stride(label: String, stride: i32) -> Result<u32, String> {
    u32::try_from(stride)
        .ok()
        .filter(|stride| *stride > 0)
        .ok_or_else(|| format!("{label} stride must be positive, got {stride}"))
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_gst_buffer_has_cuda_memory(buffer: &gst::BufferRef) -> bool {
    (0..buffer.n_memory()).any(|index| native_vulkan_is_cuda_memory(buffer.peek_memory(index)))
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_gst_cuda_context_from_buffer(
    buffer: &gst::BufferRef,
) -> Result<*mut NativeVulkanGstCudaContext, NativeVulkanError> {
    for memory_index in 0..buffer.n_memory() {
        let memory = buffer.peek_memory(memory_index);
        if !native_vulkan_is_cuda_memory(memory) {
            continue;
        }
        let cuda_memory = memory
            .as_ptr()
            .cast_mut()
            .cast::<NativeVulkanGstCudaMemory>();
        let context = unsafe { (*cuda_memory).context };
        if !context.is_null() {
            return Ok(context);
        }
    }
    Err(NativeVulkanError::Video(
        "native Vulkan CUDA buffer has no GstCudaContext".to_owned(),
    ))
}

#[cfg(feature = "native-vulkan-gst-video")]
#[allow(clippy::too_many_arguments)]
fn native_vulkan_copy_gst_cuda_plane_to_vulkan_image(
    buffer: &gst::BufferRef,
    plane_index: usize,
    plane_offset: usize,
    source_stride: u32,
    row_bytes: u32,
    height: u32,
    expected_context: *mut NativeVulkanGstCudaContext,
    stream: NativeVulkanCudaStreamHandle,
    image: &NativeVulkanCudaVideoPlane,
    label: &str,
) -> Result<NativeVulkanCudaMemoryMap, NativeVulkanError> {
    let expected_row_bytes = image
        .width
        .checked_mul(image.channels)
        .and_then(|bytes| bytes.checked_mul(image.bytes_per_channel))
        .ok_or_else(|| {
            NativeVulkanError::Video(format!("native Vulkan CUDA {label} row byte overflow"))
        })?;
    if row_bytes != expected_row_bytes || height != image.height {
        return Err(NativeVulkanError::Video(format!(
            "native Vulkan CUDA {label} plane shape mismatch: row_bytes={row_bytes} height={height} image={}x{} channels={}",
            image.width, image.height, image.channels
        )));
    }
    let plane_end = plane_offset.checked_add(1).ok_or_else(|| {
        NativeVulkanError::Video(format!("native Vulkan CUDA {label} offset overflow"))
    })?;
    let (memory_range, memory_skip) =
        buffer.find_memory(plane_offset..plane_end).ok_or_else(|| {
            NativeVulkanError::Video(format!("native Vulkan CUDA {label} plane has no memory"))
        })?;
    let memory_index = memory_range.start;
    if memory_index >= buffer.n_memory() {
        return Err(NativeVulkanError::Video(format!(
            "native Vulkan CUDA {label} memory index out of range"
        )));
    }
    let memory = buffer.peek_memory(memory_index);
    if !native_vulkan_is_cuda_memory(memory) {
        return Err(NativeVulkanError::Video(format!(
            "native Vulkan CUDA {label} plane memory is not CUDAMemory: {}",
            native_vulkan_gst_memory_type(memory)
        )));
    }
    let cuda_memory = memory
        .as_ptr()
        .cast_mut()
        .cast::<NativeVulkanGstCudaMemory>();
    let context = unsafe { (*cuda_memory).context };
    if context != expected_context {
        return Err(NativeVulkanError::Video(format!(
            "native Vulkan CUDA {label} plane context changed"
        )));
    }
    unsafe {
        gst_cuda_memory_sync(cuda_memory);
    }
    let map = NativeVulkanCudaMemoryMap::new(memory).map_err(|err| {
        NativeVulkanError::Video(format!("native Vulkan CUDA {label} map failed: {err}"))
    })?;
    let source = map
        .device_ptr()
        .checked_add(u64::try_from(memory_skip).map_err(|_| {
            NativeVulkanError::Video(format!("native Vulkan CUDA {label} memory skip too large"))
        })?)
        .ok_or_else(|| {
            NativeVulkanError::Video(format!("native Vulkan CUDA {label} source overflow"))
        })?;
    let copy = NativeVulkanCudaMemcpy2D {
        src_x_in_bytes: 0,
        src_y: 0,
        src_memory_type: CUDA_MEMORYTYPE_DEVICE,
        src_host: ptr::null(),
        src_device: source,
        src_array: ptr::null_mut(),
        src_pitch: usize::try_from(source_stride).map_err(|_| {
            NativeVulkanError::Video(format!(
                "native Vulkan CUDA {label} source stride too large"
            ))
        })?,
        dst_x_in_bytes: 0,
        dst_y: 0,
        dst_memory_type: CUDA_MEMORYTYPE_ARRAY,
        dst_host: ptr::null_mut(),
        dst_device: 0,
        dst_array: image.cuda_external_memory.array,
        dst_pitch: 0,
        width_in_bytes: usize::try_from(row_bytes).map_err(|_| {
            NativeVulkanError::Video(format!("native Vulkan CUDA {label} row bytes too large"))
        })?,
        height: usize::try_from(height).map_err(|_| {
            NativeVulkanError::Video(format!("native Vulkan CUDA {label} height too large"))
        })?,
    };
    native_vulkan_cuda_result(
        unsafe { CuMemcpy2DAsync(&copy, stream) },
        &format!("native Vulkan CUDA copy {label} plane {plane_index}"),
    )?;
    Ok(map)
}

#[cfg(feature = "native-vulkan-gst-video")]
struct NativeVulkanCudaMemoryMap {
    memory: *mut gst::ffi::GstMemory,
    info: gst::ffi::GstMapInfo,
}

#[cfg(feature = "native-vulkan-gst-video")]
impl NativeVulkanCudaMemoryMap {
    fn new(memory: &gst::MemoryRef) -> Result<Self, String> {
        let memory_ptr = memory.as_ptr().cast_mut();
        let mut info = std::mem::MaybeUninit::<gst::ffi::GstMapInfo>::zeroed();
        let mapped =
            unsafe { gst::ffi::gst_memory_map(memory_ptr, info.as_mut_ptr(), GST_MAP_READ_CUDA) }
                != gst::glib::ffi::GFALSE;
        if !mapped {
            return Err(native_vulkan_gst_memory_type(memory));
        }
        let info = unsafe { info.assume_init() };
        if info.data.is_null() {
            unsafe {
                let mut info = info;
                gst::ffi::gst_memory_unmap(memory_ptr, &mut info);
            }
            return Err("null CUDA map pointer".to_owned());
        }
        Ok(Self {
            memory: memory_ptr,
            info,
        })
    }

    fn device_ptr(&self) -> NativeVulkanCudaDevicePtr {
        self.info.data as usize as NativeVulkanCudaDevicePtr
    }
}

