        frame_payload.extend_from_slice(&[1, 0xaa, 0xab]);
        frame_payload.extend_from_slice(&[2, 0xba, 0xbb, 0xbc]);
        frame_payload.extend_from_slice(&[0, 0xca]);
        frame_payload.extend_from_slice(&[0xda, 0xdb, 0xdc, 0xdd]);

